svg.script:
(function() {
  var NS = 'http://www.w3.org/2000/svg';
  var tooltip, tooltipBg, tooltipTitle, tooltipSub, tooltipDesc, tooltipClose;

  function createTooltip() {
    tooltip = document.createElementNS(NS, 'g');
    tooltip.setAttribute('id', 'map-info-window');
    tooltip.style.display = 'none';

    tooltipBg = document.createElementNS(NS, 'rect');
tooltipBg.setAttribute('rx', '12');
    tooltipBg.setAttribute('ry', '12');
    tooltipBg.setAttribute('fill', '#0d1b2a');
    tooltipBg.setAttribute('stroke', '#1b3a5c');
    tooltipBg.setAttribute('stroke-width', '1.5');
    tooltipBg.setAttribute('opacity', '0.95');

    tooltipTitle = document.createElementNS(NS, 'text');
    tooltipTitle.setAttribute('fill', '#7dd3fc');
    tooltipTitle.setAttribute('font-family', 'system-ui,sans-serif');
    tooltipTitle.setAttribute('font-size', '15');
    tooltipTitle.setAttribute('font-weight', '600');
    tooltipTitle.setAttribute('x', '25');
    tooltipTitle.setAttribute('y', '45');

    tooltipSub = document.createElementNS(NS, 'text');
    tooltipSub.setAttribute('fill', '#00b4d8');
    tooltipSub.setAttribute('font-family', 'system-ui,sans-serif');
    tooltipSub.setAttribute('font-size', '20');
    tooltipSub.setAttribute('x', '25');
    tooltipSub.setAttribute('y', '78');

    tooltipDesc = document.createElementNS(NS, 'text');
    tooltipDesc.setAttribute('fill', '#bbb');
    tooltipDesc.setAttribute('font-family', 'system-ui,sans-serif');
    tooltipDesc.setAttribute('font-size', '18');
    tooltipDesc.setAttribute('x', '25');
    tooltipDesc.setAttribute('y', '120');

    tooltipClose = document.createElementNS(NS, 'text');
    tooltipClose.setAttribute('fill', '#4a6a8a');
    tooltipClose.setAttribute('font-family', 'system-ui,sans-serif');
    tooltipClose.setAttribute('font-size', '26');
    tooltipClose.setAttribute('x', '445');
    tooltipClose.setAttribute('y', '38');
    tooltipClose.setAttribute('cursor', 'pointer');
    tooltipClose.textContent = '\u2716';

    tooltip.appendChild(tooltipBg);
    tooltip.appendChild(tooltipTitle);
    tooltip.appendChild(tooltipSub);
    tooltip.appendChild(tooltipDesc);
    tooltip.appendChild(tooltipClose);
    document.documentElement.appendChild(tooltip);

    tooltipClose.addEventListener('click', function(e) {
      e.stopPropagation();
      hideTooltip();
    });
  }

  function showTooltip(locationEl, cx, cy) {
    var titleEl = locationEl.querySelector('title');
    if (!titleEl) return;
    var text = titleEl.textContent;
    var parts = text.split(' | ');
    var location = parts[0] || '';
    var description = parts[1] || '';

    var locParts = location.split(' - ');
    var name = locParts[0] || '';
    var place = locParts.length > 1 ? locParts[1] : '';

    tooltipTitle.textContent = name;
    tooltipSub.textContent = place;
    tooltipDesc.textContent = description;

    var tw = 480;
    var th = 160;

    tooltipBg.setAttribute('width', tw);
    tooltipBg.setAttribute('height', th);
    tooltipClose.setAttribute('x', tw - 20);

    var tx = cx + 20;
    var ty = cy - th / 2;

    if (tx + tw > 1728) tx = cx - tw - 20;
    if (ty < 0) ty = 10;
    if (ty + th > 1728) ty = 1728 - th - 10;

    tooltip.setAttribute('transform', 'translate(' + tx + ',' + ty + ')');
    tooltip.style.display = 'block';
  }

  function hideTooltip() {
    if (tooltip) tooltip.style.display = 'none';
  }

  function init() {
    createTooltip();

    var locations = document.querySelectorAll('.map-location');
    locations.forEach(function(loc) {
      var circle = loc.querySelector('.map-pin');
      if (!circle) return;
      var cx = parseFloat(circle.getAttribute('cx'));
      var cy = parseFloat(circle.getAttribute('cy'));

      loc.style.cursor = 'pointer';

      loc.addEventListener('click', function(e) {
        e.stopPropagation();
        showTooltip(loc, cx, cy);
      });
    });

    document.documentElement.addEventListener('click', function(e) {
      if (tooltip.style.display !== 'none') {
        var target = e.target;
        var inLocation = false;
        var parents = [];
        while (target && target !== document) {
          if (target.classList && target.classList.contains('map-location')) {
            inLocation = true;
            break;
          }
          target = target.parentNode;
        }
        if (!inLocation) hideTooltip();
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
